import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;

class HistoryScreen extends StatefulWidget {
  const HistoryScreen({super.key});

    @override
      State<HistoryScreen> createState() => _HistoryScreenState();
      }

      class _HistoryScreenState extends State<HistoryScreen> {
        static const String historyUrl =
              'https://fuzzy-space-goldfish-vpp5vg9rjpvv2pgp6-3000.app.github.dev/api/history';

                List<dynamic> _history = [];
                  bool _isLoading = true;
                    String? _errorText;

                      @override
                        void initState() {
                            super.initState();
                                _loadHistory();
                                  }

                                    Future<void> _loadHistory() async {
                                        setState(() {
                                              _isLoading = true;
                                                    _errorText = null;
                                                        });
                                                            try {
                                                                  final response = await http.get(Uri.parse(historyUrl));
                                                                        if (response.statusCode == 200) {
                                                                                final data = jsonDecode(utf8.decode(response.bodyBytes));
                                                                                        setState(() => _history = data);
                                                                                              } else {
                                                                                                      setState(() => _errorText = 'تعذر تحميل السجل');
                                                                                                            }
                                                                                                                } catch (e) {
                                                                                                                      setState(() => _errorText = 'تعذر الاتصال بالسيرفر');
                                                                                                                          } finally {
                                                                                                                                setState(() => _isLoading = false);
                                                                                                                                    }
                                                                                                                                      }

                                                                                                                                        Future<void> _deleteEntry(String id) async {
                                                                                                                                            try {
                                                                                                                                                  await http.delete(Uri.parse('$historyUrl/$id'));
                                                                                                                                                        _loadHistory();
                                                                                                                                                            } catch (e) {
                                                                                                                                                                  // تجاهل الخطأ، السجل بيتحدث بالمحاولة القادمة
                                                                                                                                                                      }
                                                                                                                                                                        }

                                                                                                                                                                          Color _severityColor(String? severity) {
                                                                                                                                                                              switch (severity) {
                                                                                                                                                                                    case 'عالية':
                                                                                                                                                                                            return const Color(0xFFD32F2F);
                                                                                                                                                                                                  case 'متوسطة':
                                                                                                                                                                                                          return const Color(0xFFF57C00);
                                                                                                                                                                                                                case 'منخفضة':
                                                                                                                                                                                                                        return const Color(0xFF388E3C);
                                                                                                                                                                                                                              default:
                                                                                                                                                                                                                                      return Colors.grey;
                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                              String _formatDate(String isoDate) {
                                                                                                                                                                                                                                                  try {
                                                                                                                                                                                                                                                        final date = DateTime.parse(isoDate).toLocal();
                                                                                                                                                                                                                                                              return '${date.day}/${date.month}/${date.year} - ${date.hour}:${date.minute.toString().padLeft(2, '0')}';
                                                                                                                                                                                                                                                                  } catch (e) {
                                                                                                                                                                                                                                                                        return '';
                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                              }

                                                                                                                                                                                                                                                                                @override
                                                                                                                                                                                                                                                                                  Widget build(BuildContext context) {
                                                                                                                                                                                                                                                                                      return Scaffold(
                                                                                                                                                                                                                                                                                            appBar: AppBar(
                                                                                                                                                                                                                                                                                                    title: const Text('سجل التشخيصات'),
                                                                                                                                                                                                                                                                                                            centerTitle: true,
                                                                                                                                                                                                                                                                                                                    actions: [
                                                                                                                                                                                                                                                                                                                              IconButton(
                                                                                                                                                                                                                                                                                                                                          icon: const Icon(Icons.refresh),
                                                                                                                                                                                                                                                                                                                                                      onPressed: _loadHistory,
                                                                                                                                                                                                                                                                                                                                                                  tooltip: 'تحديث',
                                                                                                                                                                                                                                                                                                                                                                            ),
                                                                                                                                                                                                                                                                                                                                                                                    ],
                                                                                                                                                                                                                                                                                                                                                                                          ),
                                                                                                                                                                                                                                                                                                                                                                                                body: _isLoading
                                                                                                                                                                                                                                                                                                                                                                                                          ? const Center(child: CircularProgressIndicator())
                                                                                                                                                                                                                                                                                                                                                                                                                    : _errorText != null
                                                                                                                                                                                                                                                                                                                                                                                                                                  ? Center(
                                                                                                                                                                                                                                                                                                                                                                                                                                                    child: Padding(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        padding: const EdgeInsets.all(24),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            child: Text(_errorText!,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    textAlign: TextAlign.center,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            style: const TextStyle(color: Colors.red)),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            : _history.isEmpty
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ? Center(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    child: Padding(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            padding: const EdgeInsets.all(24),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    child: Column(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              mainAxisSize: MainAxisSize.min,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        children: [
